// src/pages/Internship.jsx
import React, { useEffect, useState } from "react";
import { getCurrentUser } from "../utils/auth";
import "./Internship.css";

export default function Internship() {
  const [user, setUser] = useState(null);
  const [internships, setInternships] = useState([]);
  const [newInternship, setNewInternship] = useState("");

  useEffect(() => {
    const currentUser = getCurrentUser();
    if (!currentUser) {
      alert("Please login first");
      window.location.href = "/login";
    } else {
      setUser(currentUser);
    }
  }, []);

  const handleAdd = () => {
    if (newInternship.trim() === "") return;
    setInternships([...internships, newInternship]);
    setNewInternship("");
  };

  const handleDelete = (index) => {
    const updated = [...internships];
    updated.splice(index, 1);
    setInternships(updated);
  };

  const handleEdit = (index, updatedValue) => {
    const updated = [...internships];
    updated[index] = updatedValue;
    setInternships(updated);
  };

  return (
    <div className="internship-page">
      <h2>Internship Page</h2>

      {/* Allow Student to view */}
      {user && (
        <>
          {user.role !== "Student" && (
            <div className="add-box">
              <input
                type="text"
                placeholder="Add Internship"
                value={newInternship}
                onChange={(e) => setNewInternship(e.target.value)}
              />
              <button onClick={handleAdd}>Add</button>
            </div>
          )}

          <ul className="internship-list">
            {internships.map((item, index) => (
              <li key={index}>
                <span>{item}</span>

                {(user.role === "Admin" || user.role === "HR") && (
                  <button
                    onClick={() => {
                      const updated = prompt("Edit Internship", item);
                      if (updated !== null) handleEdit(index, updated);
                    }}
                  >
                    Edit
                  </button>
                )}

                {user.role === "Admin" && (
                  <button onClick={() => handleDelete(index)}>Delete</button>
                )}
              </li>
            ))}
          </ul>
        </>
      )}
    </div>
  );
}
